{"cli":"mcd extract --markdown {MCD_PATH}"}
{"sql":"select table_id, column_name, type, label, nullable from mcd_columns where table_id in ('production_quality_measurements','powertrain_calibration_specs') order by table_id, ordinal"}
{"sql":"with earliest_prod as (select lot_id, build_date from production_quality_measurements order by build_date asc, lot_id asc limit 1), earliest_cal as (select calibration_id, production_release_date from powertrain_calibration_specs order by production_release_date asc, calibration_id asc limit 1) select ep.lot_id, ep.build_date, ec.calibration_id, ec.production_release_date, case when ep.build_date < ec.production_release_date then 1 else 0 end as production_earlier_than_calibration from earliest_prod ep cross join earliest_cal ec"}
